113→// ToDeadlineData converts BigFuture data into the canonical DeadlineData format.
114→// The year parameter is the admission cycle year (e.g., 2026 for Fall 2026 entry).
115→func ToDeadlineData(bf *BigFutureData, year int) DeadlineData {
116→	sourceURL := BigFutureURL(slugFromOrgID(bf.OrgID, bf.DICode))
117→	now := time.Now().UTC().Format(time.RFC3339)
118→
119→	dd := DeadlineData{
120→		Plans:            make(map[string]DeadlinePlan),
121→		HasEarlyDecision: bf.EarlyDecision,
122→		HasEarlyAction:   bf.EarlyActionDate != "" && bf.EarlyActionDate != "null",
123→		SourceURLs:       []string{sourceURL},
124→		ExtractedAt:      now,
125→		BigfutureID:      bf.OrgID,
126→	}
127→
128→	// Early Decision
129→	if bf.EarlyDecision && bf.EarlyDecisionDate != "" {
130→		if d := convertDate(bf.EarlyDecisionDate, year); d != "" {
131→			dd.Plans[PlanEarlyDecision1] = DeadlinePlan{
132→				Deadline:   d,
133→				Binding:    true,
134→				SourceURL:  sourceURL,
135→				Confidence: "medium",
136→			}
137→		}
138→	}
139→
140→	// Early Action
141→	if bf.EarlyActionDate != "" {
142→		if d := convertDate(bf.EarlyActionDate, year); d != "" {
143→			dd.Plans[PlanEarlyAction] = DeadlinePlan{
144→				Deadline:   d,
145→				SourceURL:  sourceURL,
146→				Confidence: "medium",
147→			}
148→		}
149→	}
150→
151→	// Regular Decision
152→	if bf.RegularDecisionDate != "" {
153→		plan := DeadlinePlan{
154→			SourceURL:  sourceURL,
155→			Confidence: "medium",
156→		}
157→		if d := convertDate(bf.RegularDecisionDate, year+1); d != "" {
158→			plan.Deadline = d
159→		}
160→		// Notification date goes on the regular plan.
161→		if d := convertDate(bf.NotificationDate, year+1); d != "" {
162→			plan.Notification = d
163→		}
164→		if plan.Deadline != "" || plan.Notification != "" {
165→			dd.Plans[PlanRegular] = plan
166→		}
167→	}
168→
169→	return dd
170→}
