205→// slugFromOrgID is a fallback slug builder when we only have IDs, not a name.
206→func slugFromOrgID(orgID, diCode string) string {
207→	if orgID != "" {
208→		return orgID
209→	}
210→	return diCode
211→}
212→
213→var slugReplacer = regexp.MustCompile(`[^a-z0-9]+`)
214→
215→// SlugFromName converts an institution name to a BigFuture-style kebab-case slug.
216→func SlugFromName(name string) string {
217→	// Lowercase.
218→	s := strings.ToLower(name)
219→
220→	// Remove apostrophes and periods (BigFuture strips these rather than
221→	// replacing with hyphens).
222→	s = strings.NewReplacer("'", "", "'", "", ".", "").Replace(s)
223→
224→	// Replace any run of non-alphanumeric characters with a single hyphen.
225→	s = slugReplacer.ReplaceAllString(s, "-")
226→
227→	// Trim leading/trailing hyphens.
228→	s = strings.Trim(s, "-")
229→
230→	// Strip any remaining non-ASCII (safety net).
231→	s = strings.Map(func(r rune) rune {
232→		if r > unicode.MaxASCII {
233→			return -1
234→		}
235→		return r
236→	}, s)
237→
238→	return s
239→}
